		{ID: "vf", Path: "/var/folders/ab/cd/T/TestBaz789/001", RegisteredAt: now, LastSeen: now},
	}

	result := s.SweepProjects()

	// Expect only the real non-/tmp path remains.
	if len(result) != 1 {
